  “类型”：“对象”，
  “属性”：{
    “问题”：{
      "description": "向用户询问的问题（1-4 个问题）",
      “最小项目”：1，
      “最大项目”：4，
      “类型”：“数组”，
      “项目”：{
        “类型”：“对象”，
        “属性”：{
          “问题”：{“类型”：“字符串”}，
          “标题”：{“类型”：“字符串”}，
          “选项”：{
            “最小项目”：2，
            “最大项目”：4，
            “类型”：“数组”，
            “项目”：{
              “类型”：“对象”，
              “属性”：{
                “标签”：{“类型”：“字符串”}，
                “描述”：{“类型”：“字符串”}，
                “markdown”：{“类型”：“字符串”}
              },
              “必需”：[“标签”，“描述”]
            }
          },
          "multiSelect": { "type": "boolean", "default": false }
        },
        “必需”：[“问题”，“标题”，“选项”，“多选”]
      }
    },
    “答案”：{“类型”：“对象”}，
    “元数据”：{“类型”：“对象”}，
    “注释”：{“类型”：“对象”}
  },
  “必需”：[“问题”]
}
